    @Column({ type: 'decimal', precision: 10, scale: 2, nullable: true })
    price: number | null;  // null = utiliser le prix du produit parent

    @Column({ type: 'int', default: 0 })
    stock: number;

    @Column({ unique: true, length: 100 })
    sku: string;  // Code unique par variation

    @Column({ type: 'int', default: 5 })
    lowStockThreshold: number;  // Seuil d'alerte personnalisable

    @ManyToOne(() => Product, (product) => product.variations, { onDelete: 'CASCADE' })
    product: Product;
}
