// Dans VariationService
async checkAndReserveStock(variationId: string, quantity: number): Promise<boolean> {
    // Utilisation d'une transaction QueryRunner pour éviter les race conditions
    const queryRunner = this.dataSource.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();

    try {
        // Verrouillage pessimiste (FOR UPDATE) pour la ligne concernée
        const variation = await queryRunner.manager.findOne(Variation, {
            where: { id: variationId },
            lock: { mode: 'pessimistic_write' }
        });

        if (!variation) {
            throw new Error('Variation non trouvée');
        }

        if (variation.stock < quantity) {
            await queryRunner.rollbackTransaction();
            return false;
        }

        // Réservation temporaire (réduction du stock)
        variation.stock -= quantity;
        await queryRunner.manager.save(variation);

        // Vérification du seuil d'alerte
        const seuil = variation.lowStockThreshold ?? 5;
        if (variation.stock <= seuil && variation.stock + quantity > seuil) {
            // Le stock vient de passer sous le seuil
            console.log(`⚠️ ALERTE STOCK BAS : Variation ${variation.id} - Stock restant : ${variation.stock} (seuil: ${seuil})`);
            // En production : envoyer email, webhook, queue Bull, etc.
        }

        await queryRunner.commitTransaction();
        return true;

    } catch (error) {
        await queryRunner.rollbackTransaction();
        throw error;
    } finally {
        await queryRunner.release();
    }
}
