// src/products/subscribers/product-stock.subscriber.ts
import { EventSubscriber, EntitySubscriberInterface, UpdateEvent, InsertEvent, RemoveEvent } from 'typeorm';
import { Variation } from '../entities/variation.entity';
import { Product } from '../entities/product.entity';

@EventSubscriber()
export class ProductStockSubscriber implements EntitySubscriberInterface<Variation> {
    listenTo() {
        return Variation;
    }

    async afterInsert(event: InsertEvent<Variation>): Promise<void> {
        await this.updateProductTotalStock(event.entity.product.id, event.manager);
    }

    async afterUpdate(event: UpdateEvent<Variation>): Promise<void> {
        if (event.entity?.product?.id) {
            await this.updateProductTotalStock(event.entity.product.id, event.manager);
        }
    }

    async afterRemove(event: RemoveEvent<Variation>): Promise<void> {
        if (event.entity?.product?.id) {
            await this.updateProductTotalStock(event.entity.product.id, event.manager);
        }
    }

    private async updateProductTotalStock(productId: string, manager: any): Promise<void> {
        const result = await manager
            .createQueryBuilder(Variation, 'variation')
            .select('SUM(variation.stock)', 'total')
            .where('variation.productId = :productId', { productId })
            .getRawOne();

        await manager.update(Product, productId, {
            totalStock: parseInt(result.total) || 0
        });
    }
}
```

