CREATE OR REPLACE FUNCTION update_product_total_stock()
RETURNS TRIGGER AS $$
BEGIN
    UPDATE product
    SET "totalStock" = (
        SELECT COALESCE(SUM(stock), 0)
        FROM variation
        WHERE "productId" = NEW."productId"
    )
    WHERE id = NEW."productId";
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;
