// replenish-variation.dto.ts
export class ReplenishVariationDto {
    @IsInt()
    @Min(1)
    @ApiProperty({ example: 20, description: 'Quantité à ajouter au stock' })
    quantity: number;
}

// variation.service.ts
async replenishStock(variationId: string, quantity: number): Promise<Variation> {
    const variation = await this.variationRepository.findOne({
        where: { id: variationId },
        relations: ['product']
    });

    if (!variation) {
        throw new NotFoundException('Variation non trouvée');
    }

    const etaitEnAlerte = variation.stock <= variation.lowStockThreshold;
    const ancienStock = variation.stock;

    variation.stock += quantity;
    const nouveauStock = variation.stock;
    const estToujoursEnAlerte = nouveauStock <= variation.lowStockThreshold;

    await this.variationRepository.save(variation);

    // Notification si on sort de l'état d'alerte
    if (etaitEnAlerte && !estToujoursEnAlerte) {
        console.log(`✅ STOCK RÉTABLI : Variation ${variationId} - Nouveau stock : ${nouveauStock}`);
        // En production : envoyer email au vendeur
    }

    return variation;
}

