async getLowStockProducts(): Promise<any[]> {
    return this.productRepository
        .createQueryBuilder('product')
        .leftJoinAndSelect('product.variations', 'variation')
        .where('variation.stock <= variation.lowStockThreshold')
        .andWhere('variation.stock > 0') // Exclure ruptures totales si besoin
        .select([
            'product.id',
            'product.name',
            'variation.id',
            'variation.attributes',
            'variation.stock',
            'variation.lowStockThreshold'
        ])
        .orderBy('product.updatedAt', 'DESC')
        .getMany();
}

